public static async Task<ChatClientAgent> ProvideAgent(IWorkflowTreeViewModel tree, AgentHelper helper)
{
    // Créer un espace de travail indépendant
    var scope = tree.AsAgentScope()
        .WithPromptLanguage(AgentLanguages.English)   // Langue par défaut des invites (prompts)
        .WithOutputLanguage(AgentLanguages.Chinese)   // Langue par défaut des sorties
        .WithAutoDiscovery(assemblyName: "Lib") // Découvrir automatiquement les composants à partir de l’assembly
        .WithAutoMarkDirty(false)               // Indiquer si la vue doit être marquée automatiquement comme « sale » (dirty)
        .WithMaxToolCalls(200)                  // Nombre maximal d’appels d’outils
        .WithToolCallCallback(args =>           // Rappel lors de l’appel d’un outil
        {
            helper.ToolCalled?.Invoke();
            return Task.CompletedTask;
        })
        .WithSelectionHandler(async args => // L’agent demande à l’utilisateur de sélectionner une action à exécuter
        {
            if (helper.SelectionHandler is not null)
                await helper.SelectionHandler(args);
        })
        .WithConfirmationHandler(async args => // L’agent demande à l’utilisateur de confirmer les autorisations nécessaires à l’action
        {
            if (helper.ConfirmationHandler is not null)
                await helper.ConfirmationHandler(args);
        });

    // Niveau d’intrusion des interactions : 0 à 3
    scope.WithInteractionSafety(helper.InteractionSafety); 
    // Inscrire des invites personnalisées pour les niveaux de sécurité (efficaces uniquement pour les niveaux 1 à 3)
    foreach (var kvp in helper.InteractionSafetyPrompts)
        scope.WithInteractionSafetyPrompt(kvp.Key, kvp.Value);

    // Invite contextuelle progressive
    var contextPrompt = scope.ProvideProgressiveContextPrompt();

    // Créer le jeu d’outils MAF
    var tools = scope.ProvideTools();

    var apiKey = Environment.GetEnvironmentVariable(EnvironmentVariableName);

    var chatClient = new OpenAIClient(
        new ApiKeyCredential(apiKey),
        new OpenAIClientOptions
        {
            Endpoint = new Uri(Endpoint)
        }).GetChatClient(string.IsNullOrWhiteSpace(Model) ? "qwen-plus" : Model)
          .AsIChatClient();

    var agent = chatClient.AsAIAgent(
        instructions: contextPrompt,
        tools: tools);

    return agent;
}

